#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-17

# =============================================================================
# Stale Playground Detector
# =============================================================================
# docs/feat--{branch-slug}/ playgrounds are force-added to a gitignored dir
# during PR creation. After the PR merges there's nothing cleaning them up —
# they accumulate. This test flags playgrounds whose corresponding PR is
# MERGED or CLOSED.
#
# Advisory by default. Set STALE_PLAYGROUNDS_ENFORCE=1 to fail CI.
# Set STALE_PLAYGROUNDS_CLEAN=1 to delete flagged dirs (interactive).
# =============================================================================

set -uo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
DOCS_DIR="$REPO_ROOT/docs"

RED='\033[0;31m'; GREEN='\033[0;32m'; YELLOW='\033[1;33m'
BLUE='\033[0;34m'; BOLD='\033[1m'; NC='\033[0m'

ENFORCE="${STALE_PLAYGROUNDS_ENFORCE:-0}"
CLEAN="${STALE_PLAYGROUNDS_CLEAN:-0}"

if ! command -v gh >/dev/null 2>&1; then
    echo -e "${YELLOW}  gh CLI not available — skipping stale-playgrounds check${NC}" >&2
    exit 0
fi

echo -e "${BLUE}${BOLD}Stale playground detector (docs/feat--*)${NC}"

stale=()
open=()
orphan=()

cd "$REPO_ROOT"
shopt -s nullglob
for d in docs/feat--*; do
    [[ -d "$d" ]] || continue
    branch_slug="${d#docs/feat--}"
    # docs/feat--foo-bar-baz corresponds to feat/foo-bar-baz by convention
    # (the `--` separator stands in for `/` in dir names)
    branch="feat/${branch_slug//--/\/}"

    state=$(gh pr list --search "head:$branch" --state all --json state --jq '.[0].state // "no-pr"' 2>/dev/null || echo "no-pr")

    case "$state" in
        MERGED|CLOSED)
            stale+=("$d|$branch|$state")
            ;;
        OPEN)
            open+=("$d|$branch")
            ;;
        no-pr|"")
            orphan+=("$d")
            ;;
    esac
done

echo ""
echo -e "  ${GREEN}●${NC} Open:        ${#open[@]} (current work)"
echo -e "  ${YELLOW}●${NC} Stale:       ${#stale[@]} (PR merged/closed — candidates for removal)"
echo -e "  ${RED}●${NC} Orphan:      ${#orphan[@]} (no PR ever found — inspect manually)"
echo ""

if [[ ${#stale[@]} -gt 0 ]]; then
    echo -e "${YELLOW}Stale playgrounds (PR already merged/closed):${NC}"
    for entry in "${stale[@]}"; do
        IFS='|' read -r dir branch state <<< "$entry"
        echo -e "  $dir  ${BOLD}[$state]${NC}  $branch"
    done
    echo ""
fi

if [[ ${#orphan[@]} -gt 0 ]]; then
    echo -e "${RED}Orphan playgrounds (no matching PR):${NC}"
    for dir in "${orphan[@]}"; do
        echo -e "  $dir"
    done
    echo ""
fi

if [[ "$CLEAN" == "1" && ${#stale[@]} -gt 0 ]]; then
    echo -e "${BOLD}STALE_PLAYGROUNDS_CLEAN=1 — removing stale dirs:${NC}"
    for entry in "${stale[@]}"; do
        IFS='|' read -r dir _ _ <<< "$entry"
        rm -rf "$dir"
        echo "  removed $dir"
    done
    echo ""
fi

total_debt=$(( ${#stale[@]} + ${#orphan[@]} ))

if [[ $total_debt -eq 0 ]]; then
    echo -e "${GREEN}✓ No stale or orphan playgrounds${NC}"
    exit 0
fi

echo -e "${BLUE}To clean up:${NC}"
echo -e "  ${BOLD}STALE_PLAYGROUNDS_CLEAN=1 bash $0${NC}  — delete stale dirs"
echo -e "  ${BOLD}STALE_PLAYGROUNDS_ENFORCE=1 bash $0${NC} — fail CI on stale"
echo ""

if [[ "$ENFORCE" == "1" ]]; then
    echo -e "${RED}✗ Enforcement on — failing due to $total_debt debt item(s).${NC}"
    exit 1
fi

echo -e "${YELLOW}(Advisory mode — not failing.)${NC}"
exit 0
